DROP TABLE IF EXISTS address;
DROP TABLE IF EXISTS person;
CREATE TABLE IF NOT EXISTS person (
	id BIGSERIAL PRIMARY KEY,
	first_name VARCHAR(50),
	last_name VARCHAR(50),
	email VARCHAR(50),
	gender VARCHAR(50)
);

CREATE TABLE IF NOT EXISTS address (
	id BIGSERIAL PRIMARY KEY,
	country VARCHAR(50),
	city VARCHAR(50),
	street VARCHAR(50),
	latitude VARCHAR(50),
	longitude VARCHAR(50),
	person BIGINT,
	CONSTRAINT fk_domain_person FOREIGN KEY (person) REFERENCES person(id) ON DELETE NO ACTION ON UPDATE NO ACTION
);



